+  repo: string;
+  githubToken: string;
+  forceRefresh?: boolean;
+}
+
+export async function POST(request: NextRequest) {
+  try {
+    // Authenticate user
+    const { userId } = await auth();
+    
+    if (!userId) {
+      return NextResponse.json(
+        { error: 'Unauthorized' },
+        { status: 401 }
+      );
+    }
+
+    // Parse request body
+    const body: AnalyzeRepositoryRequest = await request.json();
+
+    // Validate required fields
+    if (!body.owner || !body.repo || !body.githubToken) {
+      return NextResponse.json(
+        {
+          error: 'Missing required fields: owner, repo, and githubToken',
+        },
